Berikut implementasi validator JSON schema murni menggunakan Python standar. Kode ini dirancang ketat (strict typing), rekursif, dan memiliki batas kedalaman untuk mencegah stack overflow.

### Implementasi Validator (`json_validator.py`)

```python
import json
from typing import Any, Dict, List, Tuple, Union

class JSONSchemaValidator:
    def __init__(self, max_depth: int = 50):
        self.max_depth = max_depth

    def validate(self, data: Any, schema: Dict, depth: int = 0) -> List[str]:
        errors = []

        # Security: Mencegah ReDoS/Stack Overflow via nested JSON
        if depth > self.max_depth:
            errors.append(f"Maximum depth ({self.max_depth}) exceeded.")
            return errors

        schema_type = schema.get("type")

        # Type Checking
        if schema_type:
            if not self._check_type(data, schema_type):
                errors.append(f"Type mismatch: expected {schema_type}, got {type(data).__name__}")
                return errors # Stop further validation if type is wrong

        # Object Validation
        if schema_type == "object" and isinstance(data, dict):
            properties = schema.get("properties", {})
            required = schema.get("required", [])

            # Check required fields
            for field in required:
                if field not in data:
                    errors.append(f"Missing required field: '{field}'")

            # Validate properties
            for key, value in data.items():
                if key in properties:
                    sub_errors = self.validate(value, properties[key], depth + 1)
                    # Prefix errors with field name
                    errors.extend([f"{key}: {err}" for err in sub_errors])
                elif schema.get("additionalProperties") is False:
                    errors.append(f"Additional property not allowed: '{key}'")

        # Array Validation
        elif schema_type == "array" and isinstance(data, list):
            items_schema = schema.get("items")
            if items_schema:
                for index, item in enumerate(data):
                    sub_errors = self.validate(item, items_schema, depth + 1)
                    errors.extend([f"index {index}: {err}" for err in sub_errors])

            # Min/Max Items
            min_items = schema.get("minItems")
            max_items = schema.get("maxItems")
            if min_items and len(data) < min_items:
                errors.append(f"Array items too few: {len(data)} < {min_items}")
            if max_items and len(data) > max_items:
                errors.append(f"Array items too many: {len(data)} > {max_items}")

        # String Validation
        elif schema_type == "string" and isinstance(data, str):
            min_len = schema.get("minLength")
            max_len = schema.get("maxLength")
            pattern = schema.get("pattern")

            if min_len and len(data) < min_len:
                errors.append(f"String too short: {len(data)} < {min_len}")
            if max_len and len(data) > max_len:
                errors.append(f"String too long: {len(data)} > {max_len}")
            if pattern:
                import re
                if not re.match(pattern, data):
                    errors.append(f"String does not match pattern: {pattern}")

        # Number/Integer Validation
        elif schema_type in ["number", "integer"] and isinstance(data, (int, float)):
            if schema_type == "integer" and isinstance(data, float) and not data.is_integer():
                errors.append("Expected integer, got float")

            minimum = schema.get("minimum")
            maximum = schema.get("maximum")

            if minimum is not None and data < minimum:
                errors.append(f"Value {data} below minimum {minimum}")
            if maximum is not None and data > maximum:
                errors.append(f"Value {data} above maximum {maximum}")

        return errors

    def _check_type(self, data: Any, schema_type: str) -> bool:
        if schema_type == "string": return isinstance(data, str)
        if schema_type == "integer": return isinstance(data, int) and not isinstance(data, bool)
        if schema_type == "number": return isinstance(data, (int, float)) and not isinstance(data, bool)
        if schema_type == "boolean": return isinstance(data, bool)
        if schema_type == "object": return isinstance(data, dict)
        if schema_type == "array": return isinstance(data, list)
        if schema_type == "null": return data is None
        return False

# Usage Example
if __name__ == "__main__":
    validator = JSONSchemaValidator()

    schema = {
        "type": "object",
        "required": ["username", "age"],
        "properties": {
            "username": {"type": "string", "minLength": 3, "pattern": "^[a-zA-Z0-9_]+$"},
            "age": {"type": "integer", "minimum": 18, "maximum": 99},
            "roles": {
                "type": "array",
                "items": {"type": "string"}
            }
        },
        "additionalProperties": False
    }

    valid_data = {"username": "admin_01", "age": 25, "roles": ["user"]}
    invalid_data = {"username": "ab", "age": "twenty", "extra": "field"}

    print("Validating valid_data:", validator.validate(valid_data, schema))
    print("Validating invalid_data:", validator.validate(invalid_data, schema))
```

### Catatan Keamanan & Teknis

1.  **Depth Limit:** Saya menambahkan `max_depth` (default 50). JSON nested yang terlalu dalam dapat menyebabkan `RecursionError` atau konsumsi memori berlebihan (DoS).
2.  **Type Strictness:** Validator ini membedakan `integer` dan `boolean` (karena di Python `bool` adalah subclass `int`). Ini penting untuk mencegah bypass tipe data.
3.  **Regex Safety:** Jika menggunakan `pattern`, pastikan regex tidak rentan terhadap ReDoS. Jangan gunakan input user langsung sebagai pola regex.
4.  **Production Warning:** Untuk sistem kritis, tetap disarankan menggunakan library battle-tested seperti `jsonschema` jika lingkungan mengizinkan. Custom validator rentan terhadap edge case yang terlewat.
5.  **Payload Size:** Sebelum validasi, pastikan ukuran payload JSON dibatasi di level server (web server config) untuk mencegah memory exhaustion sebelum parsing terjadi.

Gunakan kode ini untuk validasi input API, konfigurasi server, atau sanitasi data internal.
